import { useState } from 'react'
import './App.css'

const cardImages = [
  {"src": "../public/img/apple.png"},
  {"src": "../public/img/bananas.png"},
  {"src": "../public/img/cherries.png"},
  {"src": "../public/img/cover.png"},
  {"src": "../public/img/lemon.png"},
  {"src": "../public/img/strawberry.png"},
  {"src": "../public/img/watermelon.png"}
]

function App() {
  const [cards, setCards] = useState([])
  const [turns, setTurns] = useState(0)

  // shuffle cards
  const shuffleCards = () => {
    const shuffledCards = [...cardImages, ...cardImages]
      .sort(() => Math.random() - 0.5)
      .map((card) => ({ ...card, id: Math.random() }))
    setCards(shuffledCards)
    setTurns(0)
  }

  return (
    <div className="App">
      <h1>Magic Match</h1>
      <button onClick={shuffleCards}>New Game</button>
    </div>
  )
}

export default App
